import React, { useState } from 'react';
import {
  CContainer,
  CHeader,
  CHeaderBrand,
  CHeaderNav,
  CHeaderToggler,
  CForm,
  CFormInput,
  CButton,
  CSidebarBrand,
  CDropdown,
  CDropdownDivider,
  CDropdownHeader,
  CDropdownItem,
  CDropdownMenu,
  CDropdownToggle
} from '@coreui/react';

import CIcon from '@coreui/icons-react';
import { cilAccountLogout, cilMenu } from '@coreui/icons';

const Header = () => {
  const [sidebarShow, setSidebarShow] = useState(true);

  const handleSidebarToggle = () => {
    setSidebarShow((prev) => !prev);
  };

  return (
    <CHeader position="sticky">
      <CContainer fluid>
        {/* Brand Logo */}
        <CSidebarBrand className="d-none d-md-flex me-5" to="/">
          <img
            src="https://www.pngitem.com/pimgs/m/346-3460443_machine-learning-course-near-me-machine-learning-logo.png"
            alt="Logo"
            style={{ width: '150px', height: '60px' }}
          />
        </CSidebarBrand>

        {/* Sidebar Toggler */}
        <CHeaderToggler
          className="ps-1"
          onClick={handleSidebarToggle}
          aria-label="Toggle sidebar"
        >
          <CIcon icon={cilMenu} size="lg" />
        </CHeaderToggler>

        {/* Mobile Header Brand */}
        <CHeaderBrand className="mx-auto d-md-none" to="/">
          {/* Add mobile logo or icon here if needed */}
        </CHeaderBrand>

        {/* Search */}
        <CForm className="d-flex search m-auto ms-md-4">
          <CFormInput type="search" placeholder="Search" />
          <CButton type="submit">
            <i className="fa-solid fa-magnifying-glass" />
          </CButton>
        </CForm>

        {/* Account Dropdown */}
        <CHeaderNav className="ms-3">
          <CDropdown variant="nav-item">
            <CDropdownToggle
              placement="bottom-end"
              className="p-2 d-flex align-items-center"
              caret={false}
            >
              <i
                className="fa-regular fa-circle-user me-2"
                style={{ fontSize: '24px' }}
              />
              Dheeraj Khanna
            </CDropdownToggle>
            <CDropdownMenu className="pt-0" placement="bottom-end">
              <CDropdownHeader className="bg-light fw-semibold py-2">
                Account
              </CDropdownHeader>
              <CDropdownDivider />
              <CDropdownItem>
                <CIcon icon={cilAccountLogout} className="me-2" />
                Logout
              </CDropdownItem>
            </CDropdownMenu>
          </CDropdown>
        </CHeaderNav>
      </CContainer>
    </CHeader>
  );
};

export default Header;
